// And groups predicates with the AND operator between them.
func And(predicates ...predicate.STTTask) predicate.STTTask {
	return predicate.STTTask(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.STTTask) predicate.STTTask {
	return predicate.STTTask(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.STTTask) predicate.STTTask {
	return predicate.STTTask(sql.NotPredicates(p))
}
